package com.oneil.wellness.walkplanner.activity;import com.oneil.wellness.walkplanner.history.HistoryRepository;import java.time.OffsetDateTime;import java.util.UUID;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;@Service public class OpportunityOutcomeService{private final OpportunityOutcomeRepository repository;private final HistoryRepository history;public OpportunityOutcomeService(OpportunityOutcomeRepository r,HistoryRepository h){repository=r;history=h;}@Transactional public OpportunityOutcome record(UUID id,ActivityStatus status,ActivitySource source){if(status!=ActivityStatus.SKIPPED&&status!=ActivityStatus.DISMISSED&&status!=ActivityStatus.EXPIRED)throw new IllegalArgumentException("Unsupported opportunity outcome.");if(repository.findByRecommendationHistoryId(id).isPresent())throw new IllegalStateException("This opportunity already has a recorded outcome.");return repository.save(new OpportunityOutcome(id,status,source==null?ActivitySource.DASHBOARD:source));}@Transactional public OpportunityOutcome recordWindow(OffsetDateTime start,ActivityStatus status,ActivitySource source){UUID id=history.findTopByRecommendedStartOrderByCapturedAtDesc(start).orElseThrow(()->new IllegalArgumentException("The recommendation must be recorded before its outcome.")).getId();return record(id,status,source);}}
